class Solution {
    /**
     * Calculates the score for each element in the array.
     * The score of nums[i] is the count of j such that i < j < n and nums[i] and nums[j] have different parity.
     *
     * @param nums The input array of integers.
     * @return An array where answer[i] is the score for nums[i].
     */
    public static long[] solve(long[] nums) {
        int n = nums.length;
        if (n <= 1) {
            return new long[n];
        }

        long[] answer = new long[n];

        for (int i = 0; i < n; i++) {
            long currentNum = nums[i];
            boolean isCurrentOdd = (currentNum % 2 != 0);
            long score = 0;

            // Count odd and even numbers in the suffix nums[i+1...n-1]
            long countOddSuffix = 0;
            long countEvenSuffix = 0;
            for (int j = i + 1; j < n; j++) {
                long suffixNum = nums[j];
                if (suffixNum % 2 != 0) {
                    countOddSuffix++;
                } else {
                    countEvenSuffix++;
                }
            }

            // Calculate the score based on the parity of nums[i]
            if (isCurrentOdd) {
                // nums[i] is odd, so we count even numbers in the suffix
                score = countEvenSuffix;
            } else {
                // nums[i] is even, so we count odd numbers in the suffix
                score = countOddSuffix;
            }
            answer[i] = score;
        }

        return answer;
    }
}
