class Solution {
    public long[] solve(long[] nums) {
        int n = nums.length;
        if (n <= 1) {
            return new long[]{0};
        }

        long[] answer = new long[n];

        // Precompute prefix counts of odd and even numbers
        // prefixOdd[i] = count of odd numbers in nums[0...i-1]
        long[] prefixOdd = new long[n + 1];
        long[] prefixEven = new long[n + 1];

        for (int i = 0; i < n; i++) {
            prefixOdd[i + 1] = prefixOdd[i] + (nums[i] % 2 != 0 ? 1 : 0);
            prefixEven[i + 1] = prefixEven[i] + (nums[i] % 2 == 0 ? 1 : 0);
        }

        for (int i = 0; i < n; i++) {
            // We are looking for j such that i < j < n and parity(nums[i]) != parity(nums[j])

            // The range for j is [i+1, n-1].
            int start_j = i + 1;
            int end_j = n - 1;

            if (start_j > end_j) {
                answer[i] = 0;
                continue;
            }

            // Count of odd numbers in nums[i+1 ... n-1]
            // This is prefixOdd[n] - prefixOdd[i+1]
            long countOddAfter = prefixOdd[n] - prefixOdd[i + 1];

            // Count of even numbers in nums[i+1 ... n-1]
            // This is prefixEven[n] - prefixEven[i+1]
            long countEvenAfter = prefixEven[n] - prefixEven[i + 1];

            if (nums[i] % 2 != 0) { // nums[i] is odd
                // We need j such that nums[j] is even
                answer[i] = countEvenAfter;
            } else { // nums[i] is even
                // We need j such that nums[j] is odd
                answer[i] = countOddAfter;
            }
        }

        return answer;
    }
}
